!function(){const DOMAIN_WHITELIST=["miit.gov.cn"];location.pathname.startsWith("/redirect/go/")||document.addEventListener("click",function(e){const a=e.target.closest("a");if(!a||!a.href)return;if(a.hostname===location.hostname||function(hostname){const host=(hostname||"").toLowerCase();return DOMAIN_WHITELIST.some(function(domain){const normalizedDomain=domain.toLowerCase();return host===normalizedDomain||host.endsWith("."+normalizedDomain)})}(a.hostname)||a.href.startsWith("#")||"tel:"===a.protocol||"mailto:"===a.protocol)return;e.preventDefault();const redirectUrl="/redirect/go/"+encodeURIComponent(a.href),newTab=window.open("","_blank");newTab?(newTab.opener=null,newTab.location.href=redirectUrl):window.location.href=redirectUrl})}();